const stdout = String($json.stdout ?? '');
const stderr = String($json.stderr ?? '');
const rawExit = $json.exitCode ?? $json.code;
const exitCode = rawExit === undefined || rawExit === null || rawExit === '' ? 0 : Number(rawExit);
const commandError = String($json.error?.message ?? $json.error ?? $json.message ?? '');
const lines = stdout.trim().split(/\r?\n/).map((line) => line.trim()).filter(Boolean);
let parsed = null;
for (let i = lines.length - 1; i >= 0; i--) {
  try {
    const candidate = JSON.parse(lines[i]);
    if (candidate && typeof candidate === 'object') {
      parsed = candidate;
      break;
    }
  } catch (error) {}
}
const toInt = (value) => Number.isFinite(Number(value)) ? Number(value) : 0;
const tail = (value, max = 2500) => {
  const text = String(value ?? '');
  return text.length > max ? text.slice(text.length - max) : text;
};
const fallback = {
  ok: false,
  run_id: '',
  target_name: '台灣人壽官網',
  scheduler: 'n8n',
  summary: { total: 0, pass: 0, warn: 0, fail: 1 },
  problem_checks: [{ id: 'n8n-parse', name: 'n8n 解析 stdout', status: 'fail', detail: 'Python stdout 最後幾行找不到 JSON payload' }],
  latest_json: '',
  latest_md: '',
  screenshots: [],
  email_sent: false,
  summary_text: 'Python stdout 最後幾行找不到 JSON payload',
};
const payload = parsed || fallback;
const failCount = toInt(payload.summary?.fail);
const warnCount = toInt(payload.summary?.warn);
const nonZeroExit = Number.isFinite(exitCode) && exitCode !== 0;
const hasProblem = !payload.ok || failCount > 0 || warnCount > 0 || nonZeroExit || commandError.length > 0 || !parsed;
return [{
  json: {
    ...payload,
    should_notify_external: hasProblem,
    alert_score: hasProblem ? 1 : 0,
    command_exit_code: Number.isFinite(exitCode) ? exitCode : null,
    command_error: commandError,
    stdout_tail: tail(stdout),
    stderr_tail: tail(stderr),
  },
}];
